TriggerOraclev10g.body:
DECLARE
    vro_recibo_caja   tkr_recibos_caja%ROWTYPE;
BEGIN
    IF (:old.id_estado_suscripcion = 1 AND :new.id_estado_suscripcion = 2)
    THEN
        vro_recibo_caja.fecha_recibo := :new.fecha_compra;
        vro_recibo_caja.valor := :new.valor_compra;
        vro_recibo_caja.tipo := 2; -- Suscripcion
        vro_recibo_caja.referencia_pago := :new.referencia_pago;
        vro_recibo_caja.id_tipo := :new.id;
        pkgtkr_recibos_caja_dao.p_insertar (vro_recibo_caja);
    END IF;
END;
